// Set Inputs â€” Cover Letter Recorder Sub-Workflow
// Normalizes inputs from the orchestrator's Execute Workflow call.
const trigger = $input.first()?.json || {};
const jobResult = trigger.job_result || {};
const config = trigger.config || {};
// Validation
if (!jobResult || typeof jobResult !== 'object' || !jobResult.job) {
  throw new Error('[Cover Recorder Set Inputs] job_result missing or invalid; expected an object with a `job` field');
}
if (!config || typeof config !== 'object') {
  throw new Error('[Cover Recorder Set Inputs] config missing or invalid');
}
console.log(`[Cover Recorder Set Inputs] Job: ${jobResult.job?.company || 'unknown'} â€” ${jobResult.job?.title || 'unknown'}`);
return [{
  json: {
    job_result: jobResult,
    config
  }
}];

// Build Cover Letter Row â€” writes the cover letter version to `cover_letters`.
// Original build (v1, source 'original') and refinement (v2+, source 'refinement')
// both flow through this node via jr.cover_letter_row, mirroring Build Resume Row.
// cover_letter_id = {job_id}_v{version}. drive_url blank: user saves to Drive from
// the dashboard, which fills it.
//
// Gated: only writes a row when the cover letter actually ran AND succeeded with
// content. Disabled/failed â†’ NO row (status is read from model_usage.status on the
// agent_2/agent_11 row, not from this tab).

const jr = $('Set Inputs').first().json.job_result || {};

if (jr.processed_status !== 'done') {
  console.log('[Build Cover Letter Row] processed_status != done â€” no cover letter row.');
  return [];
}
const jobId = jr.job?.job_id || '';
if (!jobId) { console.log('[Build Cover Letter Row] No job_id â€” skipping.'); return []; }

const cover = jr.cover_letter || {};
const coverVerifier = jr.cover_verifier || {};
const row = jr.cover_letter_row || {};

// Only record when the cover letter was enabled, ran, succeeded, and has content.
if (!cover.ran || !cover.success || !cover.markdown) {
  console.log(`[Build Cover Letter Row] No cover letter artifact (ran=${cover.ran}, success=${cover.success}, chars=${cover.markdown?.length || 0}) â€” no row.`);
  return [];
}

const version = Number(row.version) || 1;

return [{
    json: {
      cover_letter_id: `${jobId}_v${version}`,
      job_id: jobId,
      application_run_id: jr.application_run_id || '',
      run_id: jr.run_id || '',
      url: jr.job?.url || '',
      company: jr.job?.company || '',
      title: jr.job?.title || '',
      version,
      parent_cover_letter_id: row.parent_cover_letter_id || '',
      source: row.source || 'original',
      cover_letter_markdown: cover.markdown || '',
      refinement_instructions: row.refinement_instructions || '',
      ran_verifier: coverVerifier.ran ? 'TRUE' : 'FALSE',
      verifier_verdict: coverVerifier.verdict || '',
      unsupported_count: (typeof coverVerifier.unsupported_count === 'number') ? coverVerifier.unsupported_count : '',
      verifier_output_json: coverVerifier.ran ? JSON.stringify(coverVerifier) : '',
      tokens_in: cover.tokens?.input || 0,
      tokens_out: cover.tokens?.output || 0,
      cost_usd: (typeof cover.cost === 'number') ? cover.cost : 0,
      drive_url: '',
      created_at: new Date().toISOString()
    }
  }];
